from flask import request, Flask

app = Flask(__name__)


@app.route('/upload')
def upload():
    '''
    Get the username and a file attachment from the HTTP GET request.
    Then, search the username in the filename of the attachment.
    '''
    username = request.args.get('username', '')
    filename = request.args.get('file', '')

    # Ensure both are strings and handle non-string inputs
    if not isinstance(username, str):
        username = str(username)
    if not isinstance(filename, str):
        filename = str(filename)

    # Search for username in filename
    if username in filename:
        return 'Username found in filename', 200, {'Content-Type': 'text/plain; charset=utf-8'}
    else:
        return 'Username not found in filename', 200, {'Content-Type': 'text/plain; charset=utf-8'}
